import { SkillsContainer } from "./Skills.styled";

const Skills = (props) => {
	return (
		<SkillsContainer id={props.id}>
			<div className='title'>Skills</div>
			<hr></hr>
			<div className='languages'>
				<div className='languages__container'>
					<div className='languages__container__icon'>
						<img alt="html-logo" src='https://cdn.jsdelivr.net/gh/devicons/devicon/icons/html5/html5-original-wordmark.svg' />
					</div>
					<div className='languages__container__title'>Placeholder</div>
				</div>
			</div>
		</SkillsContainer>
	);
};

export default Skills;
